"""Task data model.

A Task is the output of the Plan phase — a concrete action to execute.
"""

from __future__ import annotations

from datetime import datetime, timezone
from enum import Enum
from typing import Any
from uuid import UUID, uuid4

from pydantic import BaseModel, Field, ConfigDict

try:
    from enum import StrEnum
except ImportError:  # Python < 3.11
    class StrEnum(str, Enum):  # type: ignore[no-redef]
        pass


class TaskStatus(StrEnum):
    """Lifecycle status of a task."""
    PENDING = "pending"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    FAILED = "failed"
    CANCELLED = "cancelled"
    SKIPPED = "skipped"


class TaskPriority(StrEnum):
    """Priority level for task queue ordering."""
    CRITICAL = "critical"   # Must execute immediately
    HIGH = "high"
    MEDIUM = "medium"
    LOW = "low"


class Task(BaseModel):
    """A concrete action generated by the Plan phase.

    Each Task specifies exactly what tool to call, with what arguments,
    why it should be executed, and what result is expected.
    """

    model_config = ConfigDict(extra="forbid", frozen=False)

    id: UUID = Field(default_factory=uuid4, description="Unique task ID")
    priority: TaskPriority = Field(default=TaskPriority.MEDIUM, description="Execution priority")
    tool: str = Field(..., description="Tool name to invoke via ToolManager")
    action: str = Field(..., description="Action to perform on the tool")
    args: dict[str, Any] = Field(default_factory=dict, description="Arguments for the tool action")
    reason: str = Field(..., description="Why this task is necessary")
    expected_result: str = Field(..., description="What result is anticipated")
    status: TaskStatus = Field(default=TaskStatus.PENDING, description="Current task status")
    depends_on: list[UUID] = Field(default_factory=list, description="Task IDs this task depends on")
    retry_count: int = Field(default=0, ge=0, description="Number of retries attempted")
    max_retries: int = Field(default=3, ge=0, description="Maximum retry attempts")
    timeout_seconds: float = Field(default=60.0, gt=0.0, description="Task timeout")
    created_at: datetime = Field(
        default_factory=lambda: datetime.now(timezone.utc),
    )
    started_at: datetime | None = Field(default=None)
    completed_at: datetime | None = Field(default=None)
    tags: list[str] = Field(default_factory=list)
    metadata: dict[str, Any] = Field(default_factory=dict)

    @property
    def is_terminal(self) -> bool:
        """Whether this task has reached a terminal state."""
        return self.status in {
            TaskStatus.COMPLETED,
            TaskStatus.FAILED,
            TaskStatus.CANCELLED,
            TaskStatus.SKIPPED,
        }

    @property
    def can_retry(self) -> bool:
        """Whether this task can be retried."""
        return self.status == TaskStatus.FAILED and self.retry_count < self.max_retries
